# fnox shell wrappers — generated by bin/install-fnox-shell-wrappers (edit the TOOLS list there).
# Route package managers through `fnox exec` (registry token injected per-invocation).
# Bypass with `command <tool>`. Version resolution / install is delegated to mise.
npm() { fnox exec -- npm "$@"; }
npx() { fnox exec -- npx "$@"; }
yarn() { fnox exec -- yarn "$@"; }
bun() { fnox exec -- bun "$@"; }
bunx() { fnox exec -- bunx "$@"; }
pnpm() { fnox exec -- pnpm "$@"; }
pnpx() { fnox exec -- pnpx "$@"; }
